{{CSS|content=@import url('https://fonts.googleapis.com/css2?family=Rubik:wght@300;500;700&family=Amatic+SC:wght@400;700&display=swap');

:root {
    --tg-white-main: 220, 220, 220;
    --tg-white-soft: 200, 200, 200;
    --tg-white-muted: 180, 180, 180;
    --tg-white-dark: 150, 150, 150;
    --body-font: 'Rubik', sans-serif;
    --retro-font: 'Amatic SC', cursive;
    --mono-font: 'Fantasque Sans Mono', monospace;
}

.page-container .page {
    border: 2px solid rgba(var(--tg-white-soft), 0.35);
    margin: 12px auto;
    border-radius: 22px;
    background: transparent;
    box-shadow: none;
}

.theme-fandomdesktop-dark,
.theme-fandomdesktop-light {
    --theme-page-background-color: transparent;
    --theme-page-background-color--secondary: transparent;
    --theme-link-color: rgb(var(--tg-white-main));
    --theme-border-color: rgba(var(--tg-white-soft), 0.35);
    --theme-community-header-color: rgb(var(--tg-white-soft));
    --theme-sticky-nav-background-color: transparent;
    --theme-sticky-nav-text-color: rgb(var(--tg-white-main));
    --theme-sticky-nav-text-color--hover: rgb(var(--tg-white-muted));
}

a,
a:visited {
    color: rgb(var(--tg-white-main)) !important;
    text-decoration: none;
    transition: color 0.3s ease, text-shadow 0.3s ease;
}

a:hover,
a:focus {
    color: rgb(var(--tg-white-soft)) !important;
    text-shadow: 0 0 4px rgba(var(--tg-white-soft), 0.2);
}

.page-side-tools .page-side-tool {
    border: 2px solid rgba(var(--tg-white-soft), 0.35);
    border-radius: 50%;
    background-color: rgba(var(--tg-white-dark), 0.15);
    box-shadow: none;
    transition: transform 0.3s ease;
}

.page-side-tool:hover {
    transform: scale(1.08);
}

.titleblock,
.dark-titleblock {
    background: transparent;
    border: 2px solid rgba(var(--tg-white-soft), 0.35);
    border-radius: 24px;
    padding: 1rem;
    font-family: var(--retro-font);
    font-weight: 700;
    color: rgb(var(--tg-white-main));
    text-shadow: 0 0 4px rgba(var(--tg-white-soft), 0.15);
    font-size: 2.3em;
    letter-spacing: 2px;
    transform: rotate(-1deg);
    animation: soft-flicker 3s infinite alternate;
}

.progress {
    background: rgba(var(--tg-white-dark), 0.15);
    border: 2px solid rgba(var(--tg-white-soft), 0.35);
    border-radius: 15px;
    color: rgb(var(--tg-white-main));
    box-shadow: none;
}

.progress .bar {
    background: rgba(var(--tg-white-main), 0.4);
    border-radius: 12px;
    box-shadow: none;
}

h1,
h2,
h3,
h4,
h5,
h6 {
    font-family: var(--retro-font);
    color: rgb(var(--tg-white-soft));
    text-transform: uppercase;
    letter-spacing: 4px;
    text-shadow: 0 0 4px rgba(var(--tg-white-soft), 0.15);
    font-size: calc(1.5rem + 0.6vw);
}

h1 {
    font-size: calc(2rem + 1.2vw);
}

@keyframes soft-flicker {
    0%, 18%, 22%, 60%, 65%, 100% {
        opacity: 1;
        text-shadow: 0 0 4px rgba(var(--tg-white-soft), 0.15);
    }

    20%, 63% {
        opacity: 0.85;
        text-shadow: none;
    }
}
}}
